import logo from './logo.svg';
import './App.css';
import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState('');
  const [isLogin, setIsLogin] = useState(true);

  const handleLogin = async (e) => {
    e.preventDefault();

    try {
      const response = await axios.post('http://localhost:5000/login', {
        email,
        password,
      });
      setMessage(response.data.message);
    } catch (error) {
      setMessage('Login fallito: ' + error.response.data.error);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();

    try {
      const response = await axios.post('http://localhost:5000/register', {
        email,
        password,
      });
      setMessage(response.data.message);
      setIsLogin(true); // Cambia a login dopo la registrazione
    } catch (error) {
      setMessage('Registrazione fallita: ' + error.response.data.error);
    }
  };

  return (
    <div>
      <h1>{isLogin ? 'Login' : 'Registrazione'}</h1>
      <form onSubmit={isLogin ? handleLogin : handleRegister}>
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
        />
        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
        />
        <button type="submit">{isLogin ? 'Login' : 'Registrati'}</button>
      </form>
      {message && <p>{message}</p>}
      <p>
        {isLogin ? 'Non hai un account?' : 'Hai già un account?'}
        <button onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Registrati' : 'Login'}
        </button>
      </p>
    </div>
  );
}

export default App;
